__global__ void k(float* x){ int i = threadIdx.x; float v = x[i]; v = v * 1.1f + 1.0f; v = v * 1.2f + 2.0f; v = v * 1.3f + 3.0f; v = v * 1.4f + 4.0f; v = v * 1.5f + 5.0f; v = v * 1.6f + 6.0f; x[i] = v; }
